local function deserialize_session(session_str)
    if not session_str or session_str == "" then
        return nil
    end
    
    local func, err = loadstring(session_str)
    if not func then
        ngx.log(ngx.ERR, "Failed to deserialize session: ", err)
        return nil
    end
    
    local success, result = pcall(func)
    if not success then
        ngx.log(ngx.ERR, "Failed to execute session code: ", result)
        return nil
    end
    
    return result
end

local function serialize_session(session_table)
    if not session_table then
        return ""
    end
    
    local function serialize_value(v)
        local t = type(v)
        if t == "number" then
            return tostring(v)
        elseif t == "string" then
            return string.format("%q", v)
        elseif t == "boolean" then
            return tostring(v)
        elseif t == "table" then
            local parts = {}
            for key, val in pairs(v) do
                local k = type(key) == "string" and key or "[" .. serialize_value(key) .. "]"
                table.insert(parts, k .. "=" .. serialize_value(val))
            end
            return "{" .. table.concat(parts, ",") .. "}"
        else
            return "nil"
        end
    end
    
    return "return " .. serialize_value(session_table)
end

